import{_ as s,o as a,c as t,ag as n}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Erik Meijer — The Mathematical Foundations of Rx","description":"","frontmatter":{"title":"Erik Meijer — The Mathematical Foundations of Rx","category":"history","tags":["history","erik-meijer","mathematical-foundations","dual","observable","enumerable"],"related":["timeline.md","../core/Observable.md","../overview.md"],"sources":2,"updated":"2026-04-08T00:00:00.000Z"},"headers":[],"relativePath":"history/erik-meijer.md","filePath":"history/erik-meijer.md"}'),i={name:"history/erik-meijer.md"};function o(r,e,l,p,h,c){return a(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="erik-meijer-—-the-mathematical-foundations-of-rx" tabindex="-1">Erik Meijer — The Mathematical Foundations of Rx <a class="header-anchor" href="#erik-meijer-—-the-mathematical-foundations-of-rx" aria-label="Permalink to &quot;Erik Meijer — The Mathematical Foundations of Rx&quot;">​</a></h1><blockquote><p>Erik Meijer created Reactive Extensions at Microsoft Research by discovering the mathematical dual of <code>IEnumerable</code> — a single insight that unified synchronous pull collections and asynchronous push streams under the same set of operators.</p></blockquote><h2 id="the-raven-test-—-origin-of-rx" tabindex="-1">The Raven Test — Origin of Rx <a class="header-anchor" href="#the-raven-test-—-origin-of-rx" aria-label="Permalink to &quot;The Raven Test — Origin of Rx&quot;">​</a></h2><p>Erik describes his motivation using <strong>Raven tests</strong> — IQ-style puzzles where you study a grid of shapes and identify the missing one. The underlying skill is finding <em>commonalities between things</em>.</p><blockquote><p>&quot;The reason I came up with Rx is the quest to find the commonality between things.&quot;</p></blockquote><p>Looking at the programming landscape:</p><ul><li><strong>Pull collections</strong> (arrays, lists) — unified by <code>IEnumerable</code></li><li><strong>Push collections</strong> (events, async computations) — no unified interface</li></ul><p>The missing piece in the grid was an interface that unified push collections the same way <code>IEnumerable</code> unified pull ones. That missing piece is <code>IObservable</code>.</p><h2 id="the-mathematical-dual" tabindex="-1">The Mathematical Dual <a class="header-anchor" href="#the-mathematical-dual" aria-label="Permalink to &quot;The Mathematical Dual&quot;">​</a></h2><p>The core insight is a formal mathematical relationship — not just an analogy:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pull (synchronous)          Push (asynchronous)</span></span>
<span class="line"><span>─────────────────           ─────────────────────</span></span>
<span class="line"><span>IEnumerable&lt;T&gt;       dual   IObservable&lt;T&gt;</span></span>
<span class="line"><span>IEnumerator&lt;T&gt;       dual   IObserver&lt;T&gt;</span></span>
<span class="line"><span>MoveNext() / Current dual   OnNext(T value)</span></span>
<span class="line"><span>return (completed)   dual   OnCompleted()</span></span>
<span class="line"><span>throw (error)        dual   OnError(Exception)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><table tabindex="0"><thead><tr><th>IEnumerable (pull)</th><th>IObservable (push)</th></tr></thead><tbody><tr><td>You ask for values</td><td>Values are pushed to you</td></tr><tr><td>Synchronous</td><td>Synchronous or asynchronous</td></tr><tr><td><code>foreach</code> loop</td><td><code>subscribe()</code></td></tr><tr><td><code>MoveNext()</code> returns false → done</td><td><code>OnCompleted()</code> called → done</td></tr><tr><td><code>MoveNext()</code> throws → error</td><td><code>OnError()</code> called → error</td></tr></tbody></table><p><strong>The consequence</strong>: any operator that works for <code>IEnumerable</code> — <code>Select</code> (map), <code>Where</code> (filter), <code>GroupBy</code>, <code>Aggregate</code> — can be mechanically derived to work for <code>IObservable</code> by applying the duality transformation. LINQ operators over observables follow from the mathematics, not from invention.</p><h2 id="the-philosophy-focus-on-the-present" tabindex="-1">The Philosophy: Focus on the Present <a class="header-anchor" href="#the-philosophy-focus-on-the-present" aria-label="Permalink to &quot;The Philosophy: Focus on the Present&quot;">​</a></h2><blockquote><p>&quot;When you&#39;re doing stream programming you have to focus on the present — on now. There is no past, there is no future. The only thing you can hold in your hands is the current element of the stream.&quot;</p></blockquote><p>This is the philosophical stance that stream programming requires:</p><ul><li>A stream is like a <strong>mouse position</strong> — it is always at one position now, it doesn&#39;t remember where it was, it doesn&#39;t know where it&#39;s going</li><li>A stream is like a <strong>stock price</strong> — the current price is all you have</li><li>Even a <strong>baby&#39;s cry</strong> is a stream — it fires whether you&#39;re ready or not</li></ul><p>The <code>IObservable</code> interface enforces this by design: you can only react to the current value. No indexing, no history access (unless explicitly buffered).</p><h2 id="power-through-simplicity" tabindex="-1">Power Through Simplicity <a class="header-anchor" href="#power-through-simplicity" aria-label="Permalink to &quot;Power Through Simplicity&quot;">​</a></h2><blockquote><p>&quot;By limiting ourselves to a simpler interface, we get more power. By making less assumptions we can do much more.&quot;</p></blockquote><p>Removing the ability to index into a collection (no <code>array[i]</code>) seems like a restriction. But it&#39;s exactly this restriction that:</p><ul><li>Enables <strong>parallel execution</strong> — <code>map</code> functions can run in parallel (MapReduce/Hadoop)</li><li>Enables <strong>distributed computing</strong> — constant-time indexing breaks across cluster nodes</li><li>Enables <strong>lazy evaluation</strong> — the stream elements only exist at the moment they&#39;re needed</li></ul><p>The random number generator example illustrates this: there is no backing collection, just a generator. The elements only exist <em>now</em> — producing them on demand with zero memory footprint.</p><h2 id="the-two-kinds-of-streams" tabindex="-1">The Two Kinds of Streams <a class="header-anchor" href="#the-two-kinds-of-streams" aria-label="Permalink to &quot;The Two Kinds of Streams&quot;">​</a></h2><p>Erik distinguishes:</p><table tabindex="0"><thead><tr><th>Kind</th><th>Metaphor</th><th>Interface</th><th>Driven by</th></tr></thead><tbody><tr><td>Pull</td><td>Pump jack — oil only flows when you pump</td><td><code>IEnumerable</code></td><td>Consumer</td></tr><tr><td>Push</td><td>Baby — cries whether you want it or not</td><td><code>IObservable</code></td><td>Producer</td></tr></tbody></table><p>Push streams fire <strong>whether you can handle them or not</strong>. This is why backpressure and buffering operators (<code>bufferTime</code>, <code>throttleTime</code>, <code>debounceTime</code>) exist — managing the mismatch between producer speed and consumer capacity.</p><h2 id="the-original-use-case-cloud-ui" tabindex="-1">The Original Use Case: Cloud + UI <a class="header-anchor" href="#the-original-use-case-cloud-ui" aria-label="Permalink to &quot;The Original Use Case: Cloud + UI&quot;">​</a></h2><p>Erik built Rx to solve a specific architectural problem:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client (event-driven UI)  ←──────────────────→  Cloud (async web services)</span></span>
<span class="line"><span>   Mouse events (push)                              HTTP responses (push)</span></span>
<span class="line"><span>   Keyboard events (push)                           Network timeouts (push)</span></span>
<span class="line"><span>        │                                                   │</span></span>
<span class="line"><span>        └──────────────── LINQ query ────────────────────────┘</span></span>
<span class="line"><span>                    (join push streams together)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>Both sides — UI events and async network calls — are push streams. Rx gives you the same LINQ operators to compose them. A search-as-you-type feature becomes:</p><div class="language-typescript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Erik&#39;s original motivating example</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">keystrokes$.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pipe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  debounceTime</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">300</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;calm down&quot; — don&#39;t send every keystroke</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  switchMap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">q</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> search</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(q).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pipe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    timeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// cancel if server doesn&#39;t respond in 1s</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    catchError</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> of</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([]))</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ))</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>This pattern — debounce, cancel-previous, timeout — is exactly the composable reusable component Erik described: <em>&quot;things that you need to glue together these computations.&quot;</em></p><h2 id="games-as-stream-transformations" tabindex="-1">Games as Stream Transformations <a class="header-anchor" href="#games-as-stream-transformations" aria-label="Permalink to &quot;Games as Stream Transformations&quot;">​</a></h2><p>In &quot;A Playful Introduction to Rx&quot; Erik demonstrates that a <strong>game is just a stream transformation</strong>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Input streams:                    Output streams:</span></span>
<span class="line"><span>  keyboard$   ─┐                    screen updates$</span></span>
<span class="line"><span>  clock$      ─┤─ [Rx operators] ─► collision events$</span></span>
<span class="line"><span>  mouse$      ─┘                    sound effects$</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Key operators in the game implementation:</p><ul><li><code>scan</code> — physics: accumulate velocity (<code>v(t) = v(t-1) - gravity</code>)</li><li><code>combineLatest</code> — collision detection: recompute when either object moves</li><li><code>takeUntil</code> — stop trajectory stream when next jump fires</li><li><code>pairwise</code> — edge detection: detect collision → non-collision transitions</li><li><code>switchMap</code> — restart jump trajectory on each space bar press</li></ul><h2 id="combinelatest-—-stolen-from-spreadsheets" tabindex="-1">combineLatest — Stolen from Spreadsheets <a class="header-anchor" href="#combinelatest-—-stolen-from-spreadsheets" aria-label="Permalink to &quot;combineLatest — Stolen from Spreadsheets&quot;">​</a></h2><blockquote><p>&quot;This operator is exactly stolen from spreadsheets.&quot;</p></blockquote><p>An Excel cell with formula <code>=A1+B1</code> recomputes whenever A1 or B1 changes. <code>combineLatest</code> is this exact behaviour for Observable streams:</p><div class="language-typescript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Excel: =bugX + sunX (recomputes when either changes)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">combineLatest</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([bug$, sun$]).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pipe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  map</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(([</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">bug</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">sun</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> isColliding</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(bug, sun))</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Erik used this to implement collision detection in the bug game: whenever either the bug&#39;s position or the sun&#39;s position changes, check for collision.</p><h2 id="observable-collections-vs-observable-streams" tabindex="-1">Observable Collections vs Observable Streams <a class="header-anchor" href="#observable-collections-vs-observable-streams" aria-label="Permalink to &quot;Observable Collections vs Observable Streams&quot;">​</a></h2><p>Erik draws an important distinction often missed:</p><table tabindex="0"><thead><tr><th></th><th>Observable Collections</th><th>Observable Streams (Rx)</th></tr></thead><tbody><tr><td>What</td><td>A mutable list that fires change events</td><td>A sequence of values pushed over time</td></tr><tr><td>Examples</td><td><code>ObservableList&lt;T&gt;</code> in .NET/JavaFX</td><td><code>IObservable&lt;T&gt;</code></td></tr><tr><td>Role</td><td>The <strong>model</strong> — data you mutate</td><td>The <strong>processing</strong> — reactions to changes</td></tr><tr><td>Relationship</td><td>Source of events → Rx</td><td>Rx results → mutations</td></tr></tbody></table><p>The cycle:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ObservableCollection (model)</span></span>
<span class="line"><span>    → change events as Observable stream</span></span>
<span class="line"><span>    → Rx operators transform</span></span>
<span class="line"><span>    → result dispatched as mutation back to model</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>This is the foundation of <strong>ReactiveUI</strong> (.NET) and the <strong>MVU</strong> pattern.</p><h2 id="key-quotes" tabindex="-1">Key Quotes <a class="header-anchor" href="#key-quotes" aria-label="Permalink to &quot;Key Quotes&quot;">​</a></h2><blockquote><p>&quot;Once you see it, it looks obvious — but just to find the right one is not easy.&quot; — on the IEnumerable/IObservable duality</p></blockquote><blockquote><p>&quot;We are just plumbers — only we plumb with code instead of pipes.&quot; — on reactive programming composition</p></blockquote><blockquote><p>&quot;My six-year-old son is able to write games like this using Rx.&quot; — on the simplicity that emerges from the right abstraction</p></blockquote><h2 id="sources" tabindex="-1">Sources <a class="header-anchor" href="#sources" aria-label="Permalink to &quot;Sources&quot;">​</a></h2><ul><li><code>sources/talks/rx-explained-by-erik-meijer.txt</code> — 15-minute Channel 9 overview</li><li><code>sources/talks/playful-introduction-rx-erik-meijer.txt</code> — Full conference talk with game demos</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./timeline.html">timeline</a> — where Meijer&#39;s work fits in RxJS history</li><li><a href="./../core/Observable.html">Observable</a> — the IObservable interface he defined</li><li><a href="./../overview.html">overview</a> — high-level synthesis incorporating his insights</li><li><a href="./../patterns/mvu.html">mvu</a> — the MVU pattern implements his model/stream cycle</li></ul>`,57)])])}const m=s(i,[["render",o]]);export{u as __pageData,m as default};
